<template><div><h2>订单详情</h2><div v-if="order" class="detail-card"><div class="oh"><b>订单 #{{ order.id }}</b><el-tag size="small">{{ order.status }}</el-tag></div><div>金额: ¥{{ order.total_amount }}</div><div>时间: {{ order.created_at }}</div><div v-if="order.items" style="margin-top:16px"><h4>商品明细</h4><div v-for="item in order.items" :key="item.id" style="padding:8px 0;border-bottom:1px solid #F0F0F0">{{ item.product_name }} × {{ item.qty }} · ¥{{ item.price }}</div></div></div></div></template>
<script setup>import { ref, onMounted } from 'vue'; import request from '@/utils/request'; import { useRoute } from 'vue-router'; const route = useRoute(); const order = ref(null); onMounted(async () => { try { order.value = await request.get('/orders/'+route.params.id) } catch {} });</script>
<style scoped>.detail-card{background:#fff;border-radius:16px;padding:24px}.oh{display:flex;justify-content:space-between;margin-bottom:16px}</style>
